import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

public class XSSFixedCode {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Sanitize user input using ESAPI
        String sanitizedInput = ESAPI.encoder().encodeForHTML(userInput);

        String welcomeMessage = "Hello, " + sanitizedInput + "!";

        try {
            // Output the sanitized welcome message
            System.out.println(ESAPI.encoder().encodeForHTML(welcomeMessage));
        } catch (EncodingException e) {
            System.err.println("Error encoding output: " + e.getMessage());
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
